import 'package:flutter/services.dart'; import 'package:injectable/injectable.dart'; @singleton class ClipboardService { Future<void> copy(String text) => Clipboard.setData(ClipboardData(text: text)); Future<String?> paste() async { final d = await Clipboard.getData(Clipboard.kTextPlain); return d?.text; } Future<bool> hasContent() async { final d = await Clipboard.getData(Clipboard.kTextPlain); return d?.text?.isNotEmpty == true; } }